def evalInput(inputStr):
    import ast
    import builtins
    allowed_globals = {
        '__builtins__': None,
        'builtins': builtins
    }
    try:
        tree = ast.parse(inputStr, mode='eval')
        result = eval(compile(tree, '<string>', 'eval'), allowed_globals, {})
        return result
    except:
        raise ValueError("Invalid expression")

