import base64
import json

def confirmAuth(headers):
    token_str = headers.get('AuthToken', '')
    try:
        decoded = base64.b64decode(token_str)
        token_str_json = decoded.decode('utf-8')
        token = json.loads(token_str_json)
        if token and 'valid' in token and token['valid']:
            return token.get('data')
        return None
    except (base64.binascii.Error, json.JSONDecodeError):
        return None

